@@ -25814,12 +25814,24 @@ pub fn nextafter(x1: &UFuncArray, x2: &UFuncArray) -> Result<UFuncArray, UFuncEr
                 let result_bits = if a == 0.0 {
                     // Zero: return smallest subnormal towards b
